css:
#mod-fase2-1 {
  padding: 0;
}
#mod-fase2-1 .page-title {
  font-size: 24px;
  font-weight: 700;
  margin-bottom: 4px;
  color: #f1f5f9;
}
#mod-fase2-1 .page-subtitle {
  font-size: 13px;
  color: #94a3b8;
  margin-bottom: 24px;
}
#mod-fase2-1 .form-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 16px;
}
#mod-fase2-1 .form-group {
  display: flex;
  flex-direction: column;
  gap: 6px;
}
#mod-fase2-1 .form-group label {
  font-size: 12px;
  font-weight: 500;
  color: #94a3b8;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}
#mod-fase2-1 .config-input {
  padding: 10px 12px;
  border-radius: 6px;
  border: 1px solid #334155;
  background: #0f172a;
  color: #f1f5f9;
  font-size: 13px;
  outline: none;
  width: 100%;
}
#mod-fase2-1 .config-input:focus {
  border-color: #3b82f6;
}
#mod-fase2-1 .btn {
  padding: 8px 16px;
  border-radius: 6px;
  border: none;
  font-size: 13px;
  font-weight: 500;
  cursor: pointer;
  transition: 0.2s;
  display: inline-flex;
  align-items: center;
  gap: 6px;
}
#mod-fase2-1 .btn-primary {
  background: #3b82f6;
  color: #fff;
}
#mod-fase2-1 .btn-primary:hover {
  background: #2563eb;
}
#mod-fase2-1 .btn-secondary {
  background: #334155;
  color: #f1f5f9;
  border: 1px solid #475569;
}
#mod-fase2-1 .btn-secondary:hover {
  background: #475569;
}
#mod-fase2-1 .btn-danger {
  background: #ef4444;
  color: #fff;
}
#mod-fase2-1 .btn-danger:hover {
  background: #dc2626;
}
#mod-fase2-1 .btn-sm {
  padding: 5px 10px;
  font-size: 11px;
}
#mod-fase2-1 .data-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 13px;
}
#mod-fase2-1 .data-table th {
  text-align: left;
  padding: 12px 16px;
  background: #334155;
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  color: #94a3b8;
  font-weight: 600;
  border-bottom: 1px solid #475569;
}
#mod-fase2-1 .data-table td {
  padding: 12px 16px;
  border-bottom: 1px solid #334155;
  color: #f1f5f9;
}
#mod-fase2-1 .data-table tr:hover td {
  background: rgba(255,255,255,0.02);
}
#mod-fase2-1 .badge {
  padding: 3px 10px;
  border-radius: 4px;
  font-size: 11px;
  font-weight: 500;
}
#mod-fase2-1 .badge-success {
  background: rgba(16,185,129,0.15);
  color: #10b981;
}
#mod-fase2-1 .badge-warning {
  background: rgba(245,158,11,0.15);
  color: #f59e0b;
}
#mod-fase2-1 .badge-danger {
  background: rgba(239,68,68,0.15);
  color: #ef4444;
}
#mod-fase2-1 .config-panel {
  background: #1e293b;
  border: 1px solid #334155;
  border-radius: 12px;
  padding: 20px;
  margin-bottom: 24px;
}
#mod-fase2-1 .config-panel-title {
  font-size: 16px;
  font-weight: 600;
  margin-bottom: 16px;
  display: flex;
  align-items: center;
  gap: 8px;
  color: #f1f5f9;
}
#mod-fase2-1 .chart-card {
  background: #1e293b;
  border: 1px solid #334155;
  border-radius: 12px;
  padding: 20px;
  margin-bottom: 24px;
}
#mod-fase2-1 .chart-card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 16px;
}
#mod-fase2-1 .chart-card-title {
  font-size: 16px;
  font-weight: 600;
  color: #f1f5f9;
}
#mod-fase2-1 .modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.6);
  z-index: 2000;
  display: none;
  align-items: center;
  justify-content: center;
  padding: 20px;
}
#mod-fase2-1 .modal-overlay.active {
  display: flex;
}
#mod-fase2-1 .modal {
  background: #1e293b;
  border: 1px solid #334155;
  border-radius: 12px;
  width: 100%;
  max-width: 700px;
  max-height: 90vh;
  overflow-y: auto;
}
#mod-fase2-1 .modal-header {
  padding: 20px 20px 0;
  display: flex;
  align-items: center;
  justify-content: space-between;
}
#mod-fase2-1 .modal-title {
  font-size: 16px;
  font-weight: 600;
  color: #f1f5f9;
}
#mod-fase2-1 .modal-close {
  width: 32px;
  height: 32px;
  border-radius: 6px;
  background: #334155;
  border: none;
  color: #f1f5f9;
  cursor: pointer;
  font-size: 18px;
  display: flex;
  align-items: center;
  justify-content: center;
}
#mod-fase2-1 .modal-close:hover {
  background: #ef4444;
}
#mod-fase2-1 .modal-body {
  padding: 20px;
  color: #94a3b8;
  font-size: 14px;
}
#mod-fase2-1 .modal-footer {
  padding: 0 20px 20px;
  display: flex;
  justify-content: flex-end;
  gap: 10px;
}
#mod-fase2-1 .actions {
  display: flex;
  gap: 6px;
}

